const ctx = document.getElementById('healthChart').getContext('2d');

let data = {
  labels: ["Mon", "Tue", "Wed", "Thu", "Fri"],
  steps: [4000, 5000, 6000, 5500, 7000],
  calories: [200, 250, 300, 280, 350],
  sleep: [6, 7, 8, 7, 6]
};

const chart = new Chart(ctx, {
  type: 'line',
  data: {
    labels: data.labels,
    datasets: [
      { label: "Steps", data: data.steps },
      { label: "Calories", data: data.calories },
      { label: "Sleep", data: data.sleep }
    ]
  }
});

function addData() {
  const day = prompt("Enter Day:");

  data.labels.push(day);
  data.steps.push(Math.floor(Math.random()*8000));
  data.calories.push(Math.floor(Math.random()*500));
  data.sleep.push(Math.floor(Math.random()*10));

  chart.update();
}